import hmac
import hashlib

def verify_webhook(request_body, signature, secret_key):
    expected_signature = hmac.new(
        secret_key.encode(),
        request_body,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(signature, expected_signature)
